WITH stage3_rows AS (
  SELECT *
  FROM (VALUES
    ('cat_bedtime_board_books', 1, 1, 'visible', true, false, 'Best for ten minute wind down', 'Ten Minutes to Bed: Little Unicorn', 'Rhiannon Fielding', 'Penguin UK', 'https://www.penguin.co.uk/books/312671/ten-minutes-to-bed-little-unicorn-by-fielding-rhiannon/9780241348918', NULL, '£6.99', 'in_stock', '18 months+ commonly listed', 'A countdown bedtime story with familiar wind down steps and a little unicorn racing the clock toward sleep, best when you pause for one last job before lights out.', 'Just past two, bedtime works better with steps they can join than a brand new plot. Count the minutes, pause for one last job, then close. Start here when you want a short wind down they already recognise from last night.', 'Countdown bedtime steps.', NULL, 'borrow', true, NULL, 'Common gift; check shelf first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 2, 2, 'visible', true, true, 'Best for dinosaur countdown bed', 'Ten Minutes to Bed: Little Dinosaur', 'Rhiannon Fielding', 'Penguin UK', 'https://www.penguin.co.uk/books/312672/ten-minutes-to-bed-little-dinosaur-by-fielding-rhiannon/9780241532676', NULL, '£6.99', 'in_stock', '18 months+ commonly listed', 'The same ten minute bedtime countdown with a little dinosaur, so the familiar steps stay while the character swaps for a fresh read.', 'Once the unicorn countdown is known, a dinosaur swap keeps the same steps without inventing a new routine. Count the minutes, pause for one last job, then close. Second Fielding only when Little Unicorn is already the house wind down.', 'Familiar countdown with dinosaur swap.', NULL, 'borrow', true, NULL, 'Skip if Unicorn edition is not yet loved.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 3, 3, 'visible', true, true, 'Best for classic goodnight round', 'Goodnight Moon', 'Margaret Wise Brown', 'Penguin UK', 'https://www.penguin.co.uk/books/108935/goodnight-moon-by-brown-margaret-wise/9781509831975', NULL, '£6.99', 'in_stock', '18 months+ commonly listed', 'A classic goodnight round that names the room and says goodnight to each thing before sleep, paced for shared pointing on tired nights.', 'Just past two, a predictable goodnight round settles the room better than a surprise ending. Name each thing, wait for a point, then close. Keep this when the countdown books get too busy after a long day at home tonight.', 'Goodnight room round.', NULL, 'borrow', true, NULL, 'Very high duplication risk; borrow first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 4, 4, 'visible', true, true, 'Best for love you bedtime closer', 'Guess How Much I Love You', 'Sam McBratney', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/guess-how-much-i-love-you-sam-mcbratney/9781406359781', NULL, '£7.99', 'in_stock', 'Toddler to early years; overlaps this band', 'A short love you back and forth between Big Nutbrown Hare and Little Nutbrown Hare before sleep, ending in a soft closer.', 'Some nights need a love you closer more than a countdown. Trade one bigger love you, wait for a lean in, then lights out. Soft close when the countdown books already covered the wind down steps tonight at home together.', 'Love you bedtime closer.', NULL, 'borrow', true, NULL, 'High duplication risk; ask before buying.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 5, 5, 'visible', true, true, 'Best for quiet zoo goodnight', 'Goodnight Gorilla', 'Peggy Rathmann', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/goodnight-gorilla-peggy-rathmann/9781909263499', NULL, '£7.99', 'in_stock', 'Toddler picture book; overlaps this band', 'A nearly wordless goodnight zoo story where animals tip toe after the zookeeper toward bed, one stop at a time.', 'Just past two, a quiet goodnight chase can still work as a routine if you name each stop. Point, whisper goodnight, then turn. Useful when they want a gentle giggle without a long spoken plot before sleep tonight at home.', 'Quiet goodnight zoo steps.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 6, 6, 'visible', true, true, 'Best for going to bed sequence', 'The Going to Bed Book', 'Sandra Boynton', 'Penguin UK', 'https://www.penguin.co.uk/books/305833/the-going-to-bed-book-by-boynton-sandra/9780689847127', NULL, '£6.99', 'in_stock', 'Board book for toddlers', 'A short board book that walks animals through bath, brush and bed in a clear going to bed sequence you can mime together.', 'Bedtime just past two needs steps they can copy: bath, brush, bed. Read one step, wait for a mime, then turn. Good when countdown stories are already known and you want a plainer sequence on the sofa tonight together at home.', 'Bath brush bed sequence.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 7, 7, 'visible', true, true, 'Best for soft time for bed', 'Time for Bed', 'Mem Fox', 'Penguin UK', 'https://www.penguin.co.uk/books/111646/time-for-bed-by-mem-fox/9780152010485', NULL, '£6.99', 'in_stock', 'Toddler bedtime board/picture book', 'A gentle animal bedtime book with short lines that say it is time for bed again and again, paced for shared looking.', 'Some nights only need the same soft line repeated until they settle. Read one animal page, wait for a yawn cue, then turn. Soft close when the house already did bath and brush without a story fight tonight at home.', 'Repeated time for bed line.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 8, 8, 'visible', true, true, 'Best for birth night closer', 'On the Night You Were Born', 'Nancy Tillman', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/on-the-night-you-were-born-nancy-tillman/9780312601553', NULL, '£7.99', 'in_stock', 'Toddler to early years; overlaps this band', 'A lyrical night time story about the night they arrived, ending in a quiet you are loved closer for shared reading.', 'Some bedtimes want a you are loved closer more than a countdown. Stay on one night page, name the love cue, wait for a lean in, then lights out. Soft close after the familiar wind down steps are already done.', 'You are loved night closer.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_bedtime_board_books', 9, 9, 'visible', true, true, 'Best for noisy house then quiet', 'Peace at Last', 'Jill Murphy', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/peace-at-last-jill-murphy/9781509862726', NULL, '£7.99', 'in_stock', 'Picture book; early years overlap', 'A house that will not stay quiet while Mr Bear tries to sleep, ending when peace finally arrives after each noise.', 'Just past two, naming the noises that keep sleep away can settle a restless night. Pause on each noise, wait for a matching sound or a giggle, then turn toward quiet. Useful after a loud day when silence needs a story frame.', 'Noise then quiet bedtime.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_age'),
    ('cat_bedtime_board_books', 10, 10, 'visible', true, true, 'Best for bear who cannot sleep', 'Can''t You Sleep, Little Bear?', 'Martin Waddell', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/can-t-you-sleep-little-bear-martin-waddell/9780744578362', NULL, '£7.99', 'in_stock', 'Picture book; early years overlap', 'A cave bedtime story where Big Bear helps Little Bear with the dark until sleep finally comes, page by page.', 'Fear of the dark often lands just past two. Stay with Big Bear as the light gets bigger, wait for a nod, then close. Soft close when the countdown books already handled the wind down and only the dark worry remains.', 'Dark worry bedtime help.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_age'),
    ('cat_feelings_faces_books', 1, 1, 'visible', true, false, 'Best for colour feelings sorter', 'The Colour Monster', 'Anna Llenas', 'Penguin UK', 'https://www.penguin.co.uk/books/441877/the-colour-monster-a-story-about-emotions-by-llenas-anna/9781787410213', NULL, '£7.99', 'in_stock', 'Ages 2+', 'A colour sorted feelings story that gives each mood a clear jar and picture so you can name one feeling before you turn the page.', 'Just past two, the shift is naming a mood with a colour cue instead of only copying a face. Stay on one colour page, wait for a point or a matching face, then turn. Start here when you want a short feelings sort on the sofa.', 'Colour jar feelings naming.', NULL, 'borrow', true, NULL, 'Common gift; check shelf first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 2, 2, 'visible', true, true, 'Best for heart feelings pages', 'In My Heart: A Book of Feelings', 'Jo Witek', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/in-my-heart-a-book-of-feelings-jo-witek/9720855', NULL, '£12.99', 'in_stock', 'Ages 2-4 commonly listed', 'Die cut heart pages that give each feeling a body image so you can stay on one heart and name it before you turn.', 'Just past two, feelings need a body cue, not only a face on the page. Stay on one heart, wait for a word or a point, then turn. Keep the pass short so the naming stays gentle after a hard goodbye.', 'Heart body feelings naming.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 3, 3, 'visible', true, true, 'Best for bold feelings lines', 'The Feelings Book', 'Todd Parr', 'Penguin UK', 'https://www.penguin.co.uk/books/111060/the-feelings-book-by-parr-todd/9780316043465', NULL, '£7.99', 'in_stock', 'Ages 2-5 commonly listed', 'Bold pages that name everyday feelings in plain words, best when you pick one line and match it to today before you turn.', 'Just past two, short feeling lines land better than long stories. Read one line, match it to something from today, wait for a nod, then turn. Keep the naming pass short and kind on the sofa after a hard goodbye.', 'Plain feeling line naming.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 4, 4, 'visible', true, true, 'Best for grumpy face laugh', 'Grumpy Frog', 'Ed Vere', 'Penguin UK', 'https://www.penguin.co.uk/books/1110604/grumpy-frog-by-vere-ed/9780141366128', NULL, '£7.99', 'in_stock', 'Ages 2+ commonly listed', 'A funny frog story about feeling grumpy and finding friends again, best when you pause on the grumpy face and wait for a matching try.', 'Just past two, grumpy needs a face and a laugh, not a scold. Pause on the grumpy page, wait for a matching face or a word, then turn. Good when colour jars are already known and you want a story face.', 'Grumpy face matching.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 5, 5, 'visible', true, true, 'Best for colour feelings at school', 'The Colour Monster Goes to School', 'Anna Llenas', 'Penguin UK', 'https://www.penguin.co.uk/books/451838/the-colour-monster-goes-to-school-by-llenas-anna/9781787415263', NULL, '£7.99', 'in_stock', 'Ages 2+ commonly listed', 'A follow on colour feelings story set around school nerves, still using clear colour cues you can name one page at a time.', 'Once Colour Monster is familiar, school nerves need the same colour naming job. Stay on one colour page, wait for a point, then turn. Second Anna Llenas slot only when the first Colour Monster is already earning sofa time at home.', 'School nerves colour naming.', NULL, 'borrow', true, NULL, 'Skip if Colour Monster is not yet on the shelf.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 6, 6, 'visible', true, true, 'Best for worry bag story', 'The Huge Bag of Worries', 'Virginia Ironside', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/the-huge-bag-of-worries-virginia-ironside/9780340903179', NULL, '£7.99', 'in_stock', 'Picture book; toddler to early years overlap', 'A story about a bag of worries that gets lighter when worries are named and shared, best when you pause as the bag changes.', 'Just past two, worry needs a name and a share, not a long talk. Pause when the bag changes size, wait for a word or a nod, then turn so the talk stays short and kind before bed tonight at home.', 'Worry name and share.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 7, 7, 'visible', true, true, 'Best for happy cuddle board', 'Happy', 'Emma Dodd', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/happy-emma-dodd/9781788006989', NULL, '£6.99', 'in_stock', 'Board book ages 2-5 commonly listed', 'A short board book about what makes a little owl happy, ending in a close cuddle you can name and copy.', 'Some evenings only need one happy word and a cuddle, not a full feelings sort. Read the short line, name the happy cue, wait for a lean in, then close. Soft close when bigger feelings books can wait until morning.', 'Happy cuddle naming.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 8, 8, 'visible', true, true, 'Best for photo baby faces', 'Baby Faces', 'DK', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/baby-faces-dk/9780241188750', NULL, '£5.99', 'in_stock', 'Baby and toddler board book', 'Photo faces of babies showing clear expressions, best when you match one photo to a face in the room before you turn.', 'Just past two, photo faces still carry the naming job on tired evenings. Match one photo to someone in the room, wait for a try, then turn. Keep this when colour jars ask for too much talk after a long day.', 'Photo face matching.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 9, 9, 'visible', true, true, 'Best for high contrast faces', 'Baby Touch: Faces', 'Ladybird', 'Penguin UK', 'https://www.penguin.co.uk/books/313409/baby-touch-faces-a-black-and-white-book-by-ladybird/9780241391723', NULL, '£6.99', 'in_stock', 'Board book for babies and toddlers', 'A sturdy Ladybird board book of large black and white faces, sized for shared looking and simple pointing on the sofa.', 'Faces are still the social magnet just past two when colour books get busy. High contrast keeps the look simple while you name eyes and smiles. Start here when you want a short face book before busier emotion pages later.', 'High contrast face looking.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_feelings_faces_books', 10, 10, 'visible', true, true, 'Best for mirror face ending', 'Baby Touch First Focus: Faces', 'Ladybird', 'Penguin UK', 'https://www.penguin.co.uk/books/289967/faces-baby-touch-first-focus-by-ladybird/9780241243251', NULL, '£5.99', 'in_stock', 'Board book for babies and toddlers', 'A first focus faces board book with a mirror ending so they can copy one expression after looking at the pages.', 'Just past two, the job is matching a face on the page to a face in the room. Copy one expression in the mirror, wait for a try, then close. Second Ladybird only when Baby Touch Faces already covers high contrast looking.', 'Mirror face copying.', NULL, 'borrow', true, NULL, 'Cap Ladybird at two with Baby Touch Faces.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 1, 1, 'visible', true, false, 'Best for flap chat starter', 'Dear Zoo', 'Rod Campbell', 'Penguin UK', 'https://www.penguin.co.uk/books/108934/dear-zoo-by-campbell-rod/9780230747890', NULL, '£7.99', 'in_stock', '18 Months+', 'A sturdy lift the flap board book where each crate reveals a different animal to name, reject and send back to the zoo.', 'Just past two, they want to lead the page with a point and a word. Flaps that hide animals invite a short chat about too big, too fierce and just right. Start here when you want a familiar lift and talk game on the sofa.', 'Flap animal chat.', NULL, 'borrow', true, NULL, 'Very high duplication risk; borrow or bring back out first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 2, 2, 'visible', true, true, 'Best for peepo story chat', 'Peepo!', 'Janet and Allan Ahlberg', 'Penguin UK', 'https://www.penguin.co.uk/books/111124/peepo-by-ahlberg-janet/9780141337425', NULL, '£7.99', 'in_stock', '18 months+', 'A classic peepo board book following a baby through the day with holes to peep and busy home scenes to name together.', 'Daytime scenes give more to talk about than a single animal flap. Peep holes invite them to spot who is in the room next. Good when Dear Zoo is already known and you want home life chat on the page.', 'Peepo home scene chat.', NULL, 'borrow', true, NULL, 'Household staple; check shelf first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 3, 3, 'visible', true, true, 'Best for I spy rhyme chat', 'Each Peach Pear Plum', 'Janet and Allan Ahlberg', 'Penguin UK', 'https://www.penguin.co.uk/books/57304/each-peach-pear-plum-by-ahlberg-janet/9780140506396', NULL, '£7.99', 'in_stock', '18 Months+', 'A rhyme and I spy picture book where storybook characters hide in busy scenes for pointing and naming together on the sofa.', 'I spy pages stretch chat beyond flap opens for just past two. They hunt for a face in the picture and tell you who they found today. Second Ahlberg slot when Peepo already covers hole peeping at home each day.', 'I spy picture chat.', NULL, 'borrow', true, NULL, 'High borrow risk.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 4, 4, 'visible', true, true, 'Best for press and talk play', 'Press Here', 'Herve Tullet', 'Hachette Children''s UK', 'https://www.hachette.co.uk/titles/herve-tullet/press-here/9781854379571/', NULL, '£8.99', 'in_stock', 'Toddler interactive picture book; overlaps early years', 'An interactive picture book that asks them to press, shake and tip dots so the page seems to answer with a new pattern.', 'Press Here turns reading into a shared doing game with short instructions they can follow on the sofa. The chat is about what happens next after each press. Good when flaps feel old and they want a page that answers back at story time.', 'Press instruction chat.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 5, 5, 'visible', true, true, 'Best for spot the dog flaps', 'Where''s Spot?', 'Eric Hill', 'Penguin UK', 'https://www.penguin.co.uk/books/122792/wheres-spot-by-hill-eric/9780723263661', NULL, '£7.99', 'in_stock', 'Toddler flap board book', 'A lift the flap search for Spot behind doors and lids, with animals saying Spot is not there until the last reveal.', 'Search flaps keep the chat on where is he and who is behind this door. Short no answers build to a yes ending they can shout. Useful when Dear Zoo flaps are known and they want a dog hunt instead.', 'Spot search flap chat.', NULL, 'borrow', true, NULL, 'Very common hand-me-down; ask first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 6, 6, 'visible', true, true, 'Best for hungry week story', 'The Very Hungry Caterpillar', 'Eric Carle', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/the-very-hungry-caterpillar-eric-carle/9780241003008', NULL, '£7.99', 'in_stock', 'Toddler classic picture board book', 'A classic food count story with holes through fruit pages and a caterpillar that eats through the week then turns into a butterfly.', 'Counting food through the week gives a clear what next chat without needing long text on the page. They can name the fruit and notice the holes together. Good when you want a short story arc they already half know from soft play visits.', 'Food count story chat.', NULL, 'borrow', true, NULL, 'Extremely common; borrow first.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 7, 7, 'visible', true, true, 'Best for touch and reject chat', 'That''s Not My Puppy', 'Usborne', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/that-s-not-my-puppy-fiona-watt/9780746047866', NULL, '£7.99', 'in_stock', 'Baby/toddler touchy-feely board book', 'A touchy feely board book where each puppy is not quite right until the last soft page they can stroke and claim.', 'Touch patches invite a short reject and try again chat: not this one, try the next page. The ending soft patch is the yes they wait for. Good when flaps are sorted and they want texture talk on the page.', 'Touch and reject chat.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 8, 8, 'visible', true, true, 'Best for farm Spot flaps', 'Spot Goes to the Farm', 'Eric Hill', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/spot-goes-to-the-farm-eric-hill/9780723263708', NULL, '£7.99', 'in_stock', 'Toddler Spot flap board book', 'A farm visit flap book where Spot looks for animals behind barn doors and hedges for a short search and name chat.', 'Farm flaps extend the Spot search into animal naming on a different setting at home. Second Eric Hill only when Where is Spot is already loved each week. Skip if one Spot book is enough for your shelf right now.', 'Farm Spot flap chat.', NULL, 'borrow', true, NULL, 'Only if Spot search is already a hit.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 9, 9, 'visible', true, true, 'Best for dinosaur touch reject', 'That''s Not My Dinosaur', 'Usborne', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/that-s-not-my-dinosaur-fiona-watt/9781474916222', NULL, '£7.99', 'in_stock', 'Toddler touchy-feely board book', 'A dinosaur themed touchy feely board book with textured patches to stroke while rejecting each wrong dinosaur page until the last soft yes.', 'Dinosaur textures keep the reject and claim chat fresh after the puppy version at home. Second Usborne touch book only for this shelf. Useful when they already know the That is Not My pattern and want a new creature to stroke.', 'Dinosaur touch reject chat.', NULL, 'borrow', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_picture_story_books', 10, 10, 'visible', true, true, 'Best for colour see and say', 'Brown Bear, Brown Bear, What Do You See?', 'Bill Martin Jr and Eric Carle', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/brown-bear-brown-bear-what-do-you-see-bill-martin-jr/9780241135815', NULL, '£7.99', 'in_stock', 'Toddler repeating picture book', 'A repeating colour and animal see and say book with bold Eric Carle pictures and a line they can join in on.', 'Repeating lines let them join the chat before they can retell a full story alone. Colours and animals give easy points to name on each page. Good when you want a chorus style book after flap search titles on the sofa.', 'Colour see and say chat.', NULL, 'borrow', true, NULL, 'Common gift; check duplicates.', NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_potty', 1, 1, 'visible', true, false, 'Best for supported potty chair', 'BabyBjörn Potty Chair', 'BabyBjörn', 'BabyBjörn UK', 'https://www.babybjorn.co.uk/products/bathroom/potty-chair/', NULL, '£35.90', 'in_stock', 'Brand FAQ: many children interested around 18-24 months', 'A high back potty chair with armrests, a removable inner potty and a rubber strip underneath so it stays put while they climb on and off.', 'Noticing potty signs is quieter than full training: they want to sit and copy. A chair with a back and arms lets them settle without wobbling on a tippy bowl. Supported practice sitting when interest is new and you want a steady first seat.', 'Supported first sits.', NULL, 'buy', false, NULL, NULL, 'Supervise; empty and rinse after use.', 'specialist', ARRAY[]::text[], 'none'),
    ('cat_potty', 2, 2, 'visible', true, true, 'Best for simple value potty', 'LOCKIG children potty', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/lockig-childrens-potty-white-turquoise-40591581/', NULL, '£8.50', 'in_stock', 'Recommended for ages from 12 months', 'A comfy children potty with a removable insert and non-slip base, easy to empty and wipe clean after each try.', 'Early potty practice does not need a premium chair. A simple bowl with a lift out insert keeps cleaning quick after short sits at home. A plain starter when you want to try sitting practice without a big bathroom purchase this month.', 'Simple value starter potty.', NULL, 'buy', false, NULL, NULL, 'Supervise; empty insert after use.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_potty', 3, 3, 'visible', true, true, 'Best for step and potty combo', 'Bumbo Step ''n'' Potty', 'Bumbo', 'Boots', 'https://www.boots.com/bumbo-step-n-potty', NULL, '£54.99', 'in_stock', 'Toddler step and potty trainer', 'A combined step stool and potty with a removable bowl and a lid that becomes a step for sink reach after sitting practice.', 'Potty practice and sink help often arrive together just past two. One footprint that flips between sit and step saves clutter in a small bathroom at home. Useful when both jobs are starting and floor space is already full of other kit.', 'Dual step and potty.', NULL, 'buy', false, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'check_stock'),
    ('cat_potty', 4, 4, 'visible', true, true, 'Best for toilet seat helper', 'BabyBjörn Toilet Training Seat', 'BabyBjörn', 'BabyBjörn UK', 'https://www.babybjorn.co.uk/products/bathroom/toilet-training-seat/', NULL, '£35.90', 'in_stock', 'Toilet training seat for toddlers with supervision', 'A soft adjustable seat that sits on the adult toilet with a secure fit, so they can practise the big toilet with a step beside them.', 'Once the potty is a known daily sit, some children want the adult toilet. A child seat on the big toilet is the next sitting job with a steady step nearby for climbing. Second BabyBjorn bathroom piece when the chair is already in use downstairs every day.', 'Adult toilet practice.', NULL, 'buy', false, NULL, NULL, 'Supervise on adult toilet.', 'specialist', ARRAY[]::text[], 'none'),
    ('cat_potty', 5, 5, 'visible', true, true, 'Best for travel potty', 'My Carry Potty Dino', 'My Carry Potty', 'Boots', 'https://www.boots.com/my-carry-potty-dino-10285341', NULL, '£29.99', 'in_stock', 'Toddler travel potty once practice has started', 'A sealed travel potty with a carry handle and splash safe lid, shaped like a dinosaur so toilet stops away from home stay familiar.', 'Days out break potty practice just when it is getting going at home. A sealed carry potty keeps the same sitting job available in the car or at grandparents. Handy when home practice is started and trips need the same familiar seat.', 'Travel continuity.', NULL, 'buy', false, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'check_stock'),
    ('cat_shape_sorters_puzzles', 1, 1, 'visible', true, false, 'Best for birdhouse shape sorter', 'UPPSTA shape sorter', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/uppsta-shape-sorter-multicolour-90592088/', NULL, '£8.00', 'in_stock', 'Recommended for ages from 6 months', 'A birdhouse style wooden shape sorter with chunky coloured blocks that drop through matching holes and rattle inside the house.', 'Busy hands just past two want to match a shape and try again when it sticks. A clear birdhouse sorter keeps that try visible without tiny fiddly pieces. Best first sorter when they are past pure banging and into posting shapes on the floor.', 'Chunky shape posting.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_shape_sorters_puzzles', 2, 2, 'visible', true, true, 'Best for stacking sort beakers', 'UPPSTA building beakers', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/uppsta-building-beakers-multicolour-70513884/', NULL, '£4.00', 'in_stock', 'Recommended for ages from 6 months', 'A set of colourful nesting and stacking beakers for sort, stack, tip and rebuild play together on the living room floor.', 'Shape work is not only posting through holes. Nesting beakers let them sort by size and tip them out for another go on the floor. Second IKEA busy hands set when the sorter is already on the shelf at home.', 'Size sort and stack.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_shape_sorters_puzzles', 3, 3, 'visible', true, true, 'Best for classic wooden sorting cube', 'Melissa and Doug Shape Sorting Cube', 'Melissa & Doug', 'Smyths', 'https://www.smythstoys.com/uk/en-gb/toys/preschool/educational-toys/melissa-and-doug-shape-sorting-cube/p/159210', NULL, '£14.99', 'in_stock', 'Ages 2+', 'A classic wooden cube with chunky coloured shapes that post through matching holes on each face of the sturdy box.', 'A wooden cube sorter is the familiar UK shelf staple for matching shapes by hand at this age. Chunky pieces fit just past two better than tiny plastic sets. Good when you want a sturdy wooden cube instead of a birdhouse form.', 'Classic wooden sorting cube.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_stock'),
    ('cat_shape_sorters_puzzles', 4, 4, 'visible', true, true, 'Best for chunky farm puzzle', 'Melissa and Doug Chunky Pets Puzzle', 'Melissa & Doug', 'Smyths', 'https://www.smythstoys.com/uk/en-gb/toys/preschool/educational-toys/melissa-and-doug-chunky-puzzle-pets/p/186194', NULL, '£12.99', 'in_stock', 'Ages 2+', 'A wooden chunky puzzle with large lift out pet pieces that little hands can grip, lift and seat again on the board.', 'Shape sorting is one busy hands job; lift out puzzles are the next step for just past two. Chunky pet pieces let them lift, name and reseat without tiny tabs. Second Melissa and Doug slot when the cube is already sorted.', 'Chunky lift out puzzle.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_stock'),
    ('cat_shape_sorters_puzzles', 5, 5, 'visible', true, true, 'Best for Galt chunky farm puzzle', 'Galt Toys Chunky Farm Puzzle', 'Galt Toys', 'Smyths', 'https://www.smythstoys.com/uk/en-gb/toys/preschool/educational-toys/galt-toys-chunky-farm-puzzle/p/159212', NULL, '£9.99', 'in_stock', 'Ages 2+', 'A colourful chunky farm puzzle with large wooden pieces for lift, match and reseat play together on the floor mat.', 'A second chunky farm puzzle brand keeps ownership flexible if Melissa and Doug is already on the shelf. Large pieces fit busy hands just past two. Good gift when you know they already enjoy lift out animal pieces at home.', 'Chunky farm puzzle alternative.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_url'),
    ('cat_soft_graspable_balls', 1, 1, 'visible', true, false, 'Best for mini soft football', 'SPARKA soft toy football mini', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/sparka-soft-toy-football-mini-blue-red-20506758/', NULL, '£2.50', 'in_stock', 'Recommended for ages from 0 year', 'A small soft fabric football filled for gentle kicks and cuddles, sized for little hands and kind to shins indoors.', 'Confident moving just past two means kick, chase and bring it back. A mini soft football keeps that game indoors without a hard ball on the rug. Best first soft kick about when they want to join the match after breakfast.', 'Mini soft indoor football.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_soft_graspable_balls', 2, 2, 'visible', true, true, 'Best for larger soft football', 'SPARKA soft toy football', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/sparka-soft-toy-football-green-70302645/', NULL, '£4.50', 'in_stock', 'Recommended for ages from 0 year', 'A larger soft fabric football for indoor kick abouts, light enough to throw and chase without denting the skirting boards.', 'Once the mini ball is small in their hands, a fuller soft football stretches the kick along the hallway. Still soft fabric for indoor practice after tea without a hard bounce. Second IKEA soft football when they want a bigger target to chase and fetch.', 'Larger soft football.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_soft_graspable_balls', 3, 3, 'visible', true, true, 'Best for small soft vinyl football', 'Gompels Soft Football 125mm', 'Gompels', 'Gompels', 'https://www.gompels.co.uk/soft-football.html', NULL, '£3.60', 'in_stock', 'Size 2: For under 5 years', 'A bright yellow and red soft vinyl football about twelve centimetres across, filled for gentle indoor kick and catch practice.', 'Hallway kick games need a soft ball that survives carpet and sofas. This small soft football is light enough to throw back without a hard bounce. Good when SPARKA is already loved and you want a second soft kick ball upstairs.', 'Soft vinyl indoor football.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'none'),
    ('cat_soft_graspable_balls', 4, 4, 'visible', true, true, 'Best for sponge foam football', 'Gompels Sponge Football 20cm', 'Gompels', 'Gompels', 'https://www.gompels.co.uk/sponge-football-20cm.html', NULL, '£5.95', 'in_stock', 'Soft sponge foam football for schools; no under-3 exclusion on listing', 'A twenty centimetre yellow sponge foam football with panel markings, soft enough for indoor catch and kick without hard edges.', 'Some children want a fuller size ball once the mini fabric one is sorted. Soft sponge keeps indoor practice kind to furniture and shins at home. Second Gompels ball when you want foam instead of fabric fill for chase games.', 'Larger sponge foam football.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'none'),
    ('cat_soft_graspable_balls', 5, 5, 'visible', true, true, 'Best for soft foam PE ball', 'FORZA Soft Foam PE Ball', 'FORZA', 'Net World Sports', 'https://www.networldsports.co.uk/forza-foam-pe-balls.html', NULL, '£4.99', 'in_stock', 'Soft foam PE ball; no under-3 exclusion scraped on listing', 'A soft foam PE ball sold for school skills practice, light to kick and catch indoors when a hard match ball is too much.', 'Indoor PE style practice needs foam, not a hard match ball from the park. This soft foam ball gives a fuller kick target after mini fabric footballs. Fifth soft option when IKEA and Gompels already cover fabric and sponge sizes well.', 'Soft foam PE ball.', NULL, 'buy', true, NULL, NULL, NULL, 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_step_stool', 1, 1, 'visible', true, false, 'Best for low steady step', 'BabyBjörn Step Stool', 'BabyBjörn', 'BabyBjörn UK', 'https://www.babybjorn.co.uk/products/bathroom/step-stool/', NULL, '£24.90', 'in_stock', 'No fixed start age; designed for toddlers learning sink and toilet reach with supervision', 'A low plastic step about fifteen centimetres high with a full non-slip top and rubber feet, light enough for a just past two to drag to the sink.', 'I want to do it myself peaks hard just past two: handwashing and toothbrush jobs they insist on owning. A low, grippy step reaches the basin without a tall learning tower. Steady daily help at the sink when they want to climb up and join in.', 'Low steady bathroom step.', NULL, 'buy', true, NULL, 'One low step is usually enough.', 'Supervise; keep away from hobs and open windows.', 'specialist', ARRAY[]::text[], 'check_claim'),
    ('cat_step_stool', 2, 2, 'visible', true, true, 'Best for simple value step', 'FÖRSIKTIG children''s stool', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/foersiktig-childrens-stool-white-turquoise-10591318/', NULL, '£5.00', 'in_stock', 'Children’s stool; no fixed start age on listing', 'A simple IKEA children’s stool with a wide curved base, grip under the feet and a non-slip top, about thirteen centimetres high for basin reach.', 'Not every first step needs a premium brand once they want to wash hands alone. Wide base and low height still cover sink and toilet jobs. A simple spare for bathroom or kitchen when you want a second step upstairs.', 'Budget low step.', NULL, 'buy', true, NULL, NULL, 'Supervise near cooker edges.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 3, 3, 'visible', true, true, 'Best for step and potty combo', 'Bumbo Step ''n'' Potty', 'Bumbo', 'Boots', 'https://www.boots.com/bumbo-step-n-potty', NULL, '£54.99', 'in_stock', 'Toddler step and potty trainer; supervise climbing', 'A combined step stool and potty trainer with a removable bowl and a lid that becomes a step, so sink reach and potty practice share one footprint.', 'Independence jobs stack just past two: step up to wash, then sit to practise. One unit that flips between step and potty saves bathroom clutter in a small flat. Useful when space is tight and both jobs are starting together in the same bathroom.', 'Combined step and potty for small bathrooms.', NULL, 'buy', false, NULL, NULL, 'Supervise climbing; empty bowl after use.', 'good', ARRAY[]::text[], 'check_stock'),
    ('cat_step_stool', 4, 4, 'visible', true, true, 'Best for handled step stool', 'TROGEN children’s step stool', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/trogen-childrens-step-stool-yellow-80371520/', NULL, '£22.00', 'in_stock', 'Children’s step stool with handles; no fixed start age on listing', 'A light birch step stool with a carry handle cutout, sized for sink and worktop reaches when a second adult stays close.', 'Just past two, helping at the sink needs a step they can drag themselves. Stand behind, keep one hand free, then step down together. Useful when BabyBjörn is already in the bathroom and you want a spare for kitchen helping only.', 'Handled step for kitchen helping.', NULL, 'buy', true, NULL, 'Skip if FÖRSIKTIG already covers all the reach jobs you need.', 'Supervise; higher than FÖRSIKTIG — check counter edges.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_step_stool', 5, 5, 'visible', true, true, 'Best for toilet seat helper', 'BabyBjörn Toilet Training Seat', 'BabyBjörn', 'BabyBjörn UK', 'https://www.babybjorn.co.uk/products/bathroom/toilet-training-seat/', NULL, '£35.90', 'in_stock', 'Toilet training seat for toddlers moving onto the adult toilet with supervision', 'A soft, adjustable seat that sits on the adult toilet with a secure fit, so a just past two can practise the big toilet with a step beside them.', 'Once the low step is sorted, some children want the adult toilet next. A child seat on the big toilet pairs with the step for the full bathroom job. Second BabyBjörn bathroom piece when the step is already earning its keep beside the basin every day.', 'Adult toilet practice with the step.', NULL, 'buy', false, NULL, NULL, 'Supervise on the adult toilet; use with a steady step.', 'specialist', ARRAY[]::text[], 'check_url')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '25-27m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-24T11:06:00.799Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '25-27m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

